#include <stdio.h>
#include <stdlib.h>

typedef struct {int time; int idx;} Pair;
int cmpDesc(const void *a, const void *b) {
    int ta = ((Pair*)a)->time;
    int tb = ((Pair*)b)->time;
    return tb - ta; // descending
}

int main() {
    int n;
    while (scanf("%d", &n) == 1) {
        Pair *arr = (Pair*)malloc(n * sizeof(Pair));
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                int t; scanf("%d", &t);
                if (j == 0) { // first column
                    arr[i].time = t;
                    arr[i].idx = i + 1;
                }
            }
        }
        qsort(arr, n, sizeof(Pair), cmpDesc);
        for (int i = 0; i < n; ++i) {
            if (i) printf(" ");
            printf("%d", arr[i].idx);
        }
        printf("\n");
        free(arr);
    }
    return 0;
}

