const fs = require('fs');
const tokens = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let pos = 0;
let outputs = [];
while (pos < tokens.length) {
  const n = parseInt(tokens[pos++], 10);
  let pairs = [];
  for (let i = 0; i < n; i++) {
    const t = parseInt(tokens[pos++], 10); // first column
    pairs.push([t, i + 1]);
    // skip remaining n-1 entries of the row
    pos += n - 1;
  }
  pairs.sort((a, b) => b[0] - a[0]);
  outputs.push(pairs.map(p => p[1]).join(' '));
}
